/** Decode a base64 PNG string to Uint8Array */
export function b64ToUint8Array(b64: string): Uint8Array {
  const buf = Buffer.from(b64, "base64");
  return new Uint8Array(buf.buffer, buf.byteOffset, buf.byteLength);
}
